          {selected=='A'? (<p>This is {selected}</p>) :selected=='B'? (<p>This is 1</p>) : selected=='C'? (<p>This is 2</p>) :(<p>This is 3</p>) }
      </div>

      <input type="text" onChange={(e)=>sethOLD(e.target.value)}  name="" id="" />
