            <option value="Sylhet">Sylhet</option>
            <option value="Dhaka">Dhaka</option>
            <option value="Ctg">Ctg</option>
          </select>

      </div>)

      })}


      {array?array.map((item,index)=>{
        if(item.name!=''){
          (
            <div>
              <p>This is from input field{index+1}</p>
              <p>Name: {item.name}</p>
              <p>Address: {item.address}</p>
            </div>
            
